import { InjectQueue } from '@nestjs/bullmq';
import { Injectable } from '@nestjs/common';
import type { CheckoutCompletedEventPayload } from '@smartcart/shared-types';
import { Queue } from 'bullmq';
import {
  ANALYTICS_JOB,
  ANALYTICS_JOB_OPTIONS,
  ANALYTICS_QUEUE,
} from '../../common/queues/queue.config';

/**
 * Low-level producer onto the analytics queue (README §2.2 Long-Running Process
 * Separation). `BullMqEventPublisher` (the IEventPublisher port) delegates here,
 * keeping all enqueue logic for the consumer-profiling pipeline in one place.
 */
@Injectable()
export class AnalyticsQueueProducer {
  constructor(
    @InjectQueue(ANALYTICS_QUEUE) private readonly queue: Queue,
  ) {}

  async enqueueProfileUpdate(
    event: CheckoutCompletedEventPayload,
  ): Promise<void> {
    await this.queue.add(ANALYTICS_JOB, event, ANALYTICS_JOB_OPTIONS);
  }
}
